using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer.Tools;

[McpServerToolType]
public static class EchoTool
{
    [McpServerTool, Description("Echoes the input message back to the caller.")]
    public static string Echo([Description("The message to echo")] string message)
        => $"Echo: {message}";

    [McpServerTool, Description("Returns the current server time in UTC.")]
    public static string GetServerTime()
        => $"Server time: {DateTime.UtcNow:O}";
}

using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer.Resources;

[McpServerResourceType]
public static class ConfigResource
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "Application Settings",
        Description = "Returns the current application configuration data.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Environment = "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { DarkMode = true, BetaAccess = false }
        };

        return System.Text.Json.JsonSerializer.Serialize(config,
            new System.Text.Json.JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://app/version",
        Name = "App Version",
        Description = "Returns the application version information.")]
    public static string GetVersion()
    {
        return System.Text.Json.JsonSerializer.Serialize(new
        {
            Version = "1.0.0",
            BuildDate = "2026-04-03"
        });
    }
}

