using McpHttpServer.Tools;
using McpHttpServer.Resources;

var builder = WebApplication.CreateBuilder(args);

// Register the MCP server with HTTP (Streamable HTTP) transport.
// WithTools/WithResources scan the attributed types for [McpServerTool] / [McpServerResource].
builder.Services
    .AddMcpServer()
    .WithHttpTransport()
    .WithTools<EchoTool>()
    .WithResources<ConfigResource>();

var app = builder.Build();

// MapMcp exposes the MCP endpoint (default path: /mcp).
// Clients POST JSON-RPC requests here; the server replies over the same connection.
app.MapMcp();

app.Run();

