var builder = WebApplication.CreateBuilder(args);

// Register the MCP server with HTTP (Streamable HTTP) transport.
// WithToolsFromAssembly/WithResourcesFromAssembly scan for [McpServerToolType] / [McpServerResourceType].
builder.Services
    .AddMcpServer()
    .WithHttpTransport()
    .WithToolsFromAssembly()
    .WithResourcesFromAssembly();

var app = builder.Build();

// MapMcp exposes the MCP endpoint (default path: /mcp).
// Clients POST JSON-RPC requests here; the server replies over the same connection.
app.MapMcp();

app.Run();

